# Minimal dataset format for SFT — (instruction, response) pairs as chat
import json

EXAMPLES = [
    {
        "messages": [
            {
                "role": "system",
                "content": "Extract company names, locations, and dates from the text. Return JSON."
            },
            {
                "role": "user",
                "content": "Apple Inc. announced record revenue in Cupertino on November 2, 2024."
            },
            {
                "role": "assistant",
                "content": json.dumps({
                    "companies": ["Apple Inc."],
                    "locations": ["Cupertino"],
                    "dates": ["November 2, 2024"]
                }, indent=2)
            }
        ]
    }
    # Repeat with varied phrasing, entity types, and edge cases
]

# Quality checks before writing
for i, ex in enumerate(EXAMPLES):
    msgs = ex["messages"]
    assert msgs[-1]["role"] == "assistant", f"Example {i}: last turn must be assistant"
    try:
        json.loads(msgs[-1]["content"])  # verify JSON output is valid
    except json.JSONDecodeError as e:
        raise ValueError(f"Example {i} has invalid JSON output: {e}")

with open("data/entity_extraction.jsonl", "w") as f:
    for ex in EXAMPLES:
        f.write(json.dumps(ex) + "\n")

print(f"Wrote {len(EXAMPLES)} training examples")
